public List<Transaction> getHistoryByAccount(String id) {
    List<Transaction> result = new ArrayList<>();
    for (Transaction t : history) {
        if (id.equals(t.getFrom()) || id.equals(t.getTo())) {
            result.add(t);
        }
    }
    return result;
}

